+        let contract = BrowserHostServicesContract::V1;
+        assert!(
+            contract
+                .required_capabilities
+                .contains(&"host-turn wakeups"),
+            "browser contract must require host-turn wakeups"
+        );
+        assert!(
+            contract
+                .required_capabilities
